VALUES
  ('dietitian-moex-09434', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '當患者說：「我可以在家中吃低脂飲食，但我常常出差，而且在飯店沒有辦法點到低脂的食物」。此時 營養師接著說：「你在家中可以照著指示吃，可是在外進食就有困難。」請問營養師此種傾聽方式為：', '["澄清（clarifying）", "簡述語意（paraphrasing）", "反映（reflecting）", "摘要（summarizing）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09435', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '自我表露（self-disclosure）是營養師在諮詢時分享他們自己資訊的方式，其目的在於：', '["降低彼此因角色差異造成的距離", "辨識可以提供給個案的訊息", "評估提供給個案的訊息是否有用", "找出個案想傳達的訊息"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09436', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '一項針對青少年所進行的「天天五蔬果」宣導活動內容包括：讓青少年瞭解癌症對生命與生活的威脅， 告訴其增加蔬果攝取的好處以及如何養成多吃蔬果的飲食習慣等等。請問此種營養教育主要根據何種理 論？', '["Health Belief Model", "Assure Model", "Community Organization", "Social Marketing"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09437', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '醫院常見各種疾病的病友團體，此類組織可視為下列何種營養教育理論的應用與延伸？', '["Diffusion of Innovations", "Stages of Change", "Social Cognitive Theory", "Social Support"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09438', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '當一位糖尿病患者相信他自己有換算不同食物份量的能力時，此種能力稱為：', '["期望（expectation）", "增強（reinforcement）", "自我效能（self-efficacy）", "行為能力（behavior capacity）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09439', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何種體檢項目不包括在主觀整體評估（Subjective Global Assessment）?', '["缺少皮下脂肪", "足踝水腫", "腹水", "脫水"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09440', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關使用頭髮為檢體進行營養評估，下列敘述何者錯誤？', '["使用此檢體的優點是檢體容易保存", "評估結果反映短期之微量元素營養狀況", "檢體必須仔細清洗，以防外源性污染", "常用來評估微量元素之營養狀況"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09441', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某成年男性之血液分析結果如下：血清葉酸濃度為2.3 ng/mL，紅血球葉酸濃度為150 ng/mL，則此男性 之葉酸營養狀況屬於：', '["葉酸營養狀況正常", "早期葉酸負平衡（early negative folate balance）", "葉酸耗損（folate depletion）", "葉酸缺乏性紅血球生成（folate deficiency erythropoiesis）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09442', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者可用以評估維生素B 的營養狀況？ 6', '["紅血球轉氨酶活性係數", "紅血球轉酮酶活性係數", "紅血球榖胱甘肽還原酶活性係數", "紅血球乳酸脫氫酶活性係數"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09443', 'dietitian', 'dietitian-moex-096-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '二十四小時尿液之三甲基組胺酸 (3-methylhistidine) 排出量：', '["與人體骨骼肌及去脂組織（fat-free mass）含量成正比", "會因肉類攝取量增加而下降", "會因最近的激烈運動而降低", "與脂肪攝取量成正比"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:53+00:00", "source_pdf_sha1": "6e9113a73365", "answer_pdf_sha1": "a6e0529ac22f", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
